const config = $('Get Config').first().json;
const today = new Date().toISOString().split('T')[0];

const sections = [
  { name: 'System Architecture Overview', prompt: 'Write a comprehensive overview of the IntraWeb OS. Cover all 17 systems, how they connect to each other, the data flow between them, the full tech stack (n8n, HubSpot, Google Sheets, Google Drive, Twilio, Resend, Anthropic Claude, ElevenLabs, Google Chat). Include a narrative description of how a lead flows through the entire system from sourcing to project completion.' },
  { name: 'Credentials & Access Master Reference', prompt: 'Document every credential used: HubSpot API, Twilio Account, Google Service Account, ElevenLabs API, Resend API, Anthropic API, Google Chat Webhook, Google Maps API. For each: where to find it, which systems use it, how to rotate it safely without breaking workflows.' },
  { name: 'System by System Runbook', prompt: 'For each of the 17 systems (Lead Sourcing, Voice Qualification, Outreach Sequence, Onboarding, Proposals, Invoicing, LinkedIn Content, Weekly Updates, Reporting Dashboard, Health Monitoring, Referral/Reactivation, Command Center, Docs Generator, Manual Generator): plain English description, trigger mechanism, expected outputs, dependencies on other systems, how to test it, common failure modes, how to fix failures, how to modify behavior.' },
  { name: 'Daily Weekly Monthly Operating Checklist', prompt: 'Create a structured checklist. Daily: what to check (Google Chat alerts, failed executions). Weekly: what to review (pipeline status, client health scores, LinkedIn queue). Monthly: what actions to take (credential rotation check, sheet cleanup, performance review). Mark what is fully automated vs needs human attention.' },
  { name: 'HubSpot Configuration Reference', prompt: 'Document every custom property (lead_score, lead_source, lead_status, industry, pain_point, outreach_sequence_status, replied_flag, booking_flag, decision_maker, budget_mentioned, employee_count, tier, proposal_sent_date, contract_signed_date, client_health_score, last_activity_date, monthly_retainer, deal_pain_points, client_drive_folder_id), all deal stages, pipeline structure, how to add clients manually.' },
  { name: 'Google Sheets Reference', prompt: 'Document every tab (Automations Log, Leads, Pipeline, Clients, Revenue, LinkedIn, Summary, Proposals), every column, what populates each tab, how to manually log entries, how to read the dashboard, data retention policies.' },
  { name: 'Adding & Offboarding Clients', prompt: 'Step-by-step for adding a new client: HubSpot deal creation, stage progression, what triggers automatically, pre-launch checklist. For offboarding: how to deactivate a client, archive data, stop automated communications, update billing.' },
  { name: 'Troubleshooting Guide', prompt: 'How to read n8n execution logs, test webhook endpoints, resend failed messages, restart stuck workflows, identify cascading failures when one sub-workflow goes down, common error patterns and their fixes.' },
  { name: 'Scaling Guide', prompt: 'How to add contractors to the workflow (permissions, access, what they can modify), how to add new industry verticals, how to clone the client stack for additional businesses, when to upgrade service tiers, capacity planning.' },
  { name: 'Changelog Template', prompt: 'Provide a changelog template with columns: Date, System/Workflow Modified, Change Description, Changed By, Reason, Rollback Instructions. Include instructions for keeping the changelog current.' }
];

return sections.map(s => ({
  json: {
    sectionName: s.name,
    systemPrompt: 'You are writing the owner\'s manual for the IntraWeb Technologies internal operating system. This is a technical reference document for the sole operator (John, the founder). Tone: clear, direct, practical. No corporate speak. Write in markdown format. Be specific and actionable. Include exact property names, workflow names, and configuration values where relevant.',
    userPrompt: s.prompt,
    maxTokens: 4000
  }
}));

const MAX = 10;
const sectionPrompts = $('Prep Section Prompts').all().slice(0, MAX);
const sections = $input.all().slice(0, MAX);
const config = $('Get Config').first().json;
const today = new Date().toISOString().split('T')[0];

const sectionMarkdown = (item) => {
  const j = item.json || {};
  if (j.data && typeof j.data.text === 'string' && j.data.text.trim()) return j.data.text.trim();
  if (typeof j.text === 'string' && j.text.trim()) return j.text.trim();
  if (j.success === false && j.error) return `**Section failed:** ${String(j.error)}`;
  return '*No content was returned for this section.*';
};

let markdown = `# IntraWeb OS — Owner's Manual\n\n`;
markdown += `**Generated:** ${today}\n`;
markdown += `**Version:** 1.0\n`;
markdown += `**Owner:** ${config.owner.name} | ${config.owner.companyName}\n\n`;
markdown += `---\n\n`;
markdown += `## Table of Contents\n\n`;

for (let i = 0; i < sectionPrompts.length; i++) {
  markdown += `${i + 1}. ${sectionPrompts[i].json.sectionName}\n`;
}

markdown += `\n---\n\n`;

const n = Math.min(sectionPrompts.length, sections.length);
for (let i = 0; i < n; i++) {
  const content = sectionMarkdown(sections[i]);
  markdown += `## ${i + 1}. ${sectionPrompts[i].json.sectionName}\n\n`;
  markdown += content;
  markdown += `\n\n---\n\n`;
}

const escapeHtml = (s) =>
  String(s)
    .replace(/&/g, '&amp;')
    .replace(/</g, '&lt;')
    .replace(/>/g, '&gt;');

const html = `<!DOCTYPE html><html><head><meta charset="utf-8"/><style>
  @import url('https://fonts.googleapis.com/css2?family=DM+Sans:wght@400;500;700&display=swap');
  body { font-family: 'DM Sans', Arial, sans-serif; color: #333; line-height: 1.55; max-width: 900px; margin: 0 auto; padding: 40px; }
  pre.manual-md { white-space: pre-wrap; word-wrap: break-word; font-family: 'DM Sans', Arial, sans-serif; font-size: 14px; }
  .header { background: #1a1f2e; color: white; padding: 40px; margin: -40px -40px 40px; text-align: center; }
  .header h1 { color: #3d8b8b; margin: 0; }
</style></head><body><div class="header"><h1>IntraWeb OS</h1><p>Owner's Manual</p><p>${today}</p></div><pre class="manual-md">${escapeHtml(markdown)}</pre></body></html>`;

return [{
  json: {
    markdown,
    html,
    fileName: `IntraWeb-OS-Owners-Manual-${today}.pdf`
  }
}];

const items = $input.all().slice(0, 1);
const out = [];

for (let i = 0; i < items.length; i++) {
  const item = items[i];
  const j = item.json || {};
  const fileName =
    (j.data && j.data.fileName) ||
    j.fileName ||
    $('Assemble Manual').first().json.fileName ||
    'IntraWeb-OS-Owners-Manual.pdf';
  const inlineBinary = item.binary && item.binary.data && item.binary.data.data;
  let b64 = typeof inlineBinary === 'string' && inlineBinary !== 'filesystem-v2' ? inlineBinary : '';

  if (!b64 && item.binary && item.binary.data) {
    const pdfBuffer = await this.helpers.getBinaryDataBuffer(i, 'data');
    b64 = pdfBuffer.toString('base64');
  }

  if (!b64 && j.data && typeof j.data.pdfBase64 === 'string') {
    b64 = j.data.pdfBase64;
  }

  if (!b64) {
    throw new Error(
      'Attach PDF Binary: missing usable PDF bytes for ' +
        fileName +
        '. ' +
        JSON.stringify({ success: j.success, error: j.error }).slice(0, 400),
    );
  }

  out.push({
    json: j,
    binary: {
      data: {
        data: b64,
        mimeType: (j.data && j.data.mimeType) || 'application/pdf',
        fileName,
        fileExtension: 'pdf'
      }
    }
  });
}

return out;

const driveLink = 'https://drive.google.com/file/d/' + $('Upload to Drive').first().json.id;

return [{
  json: {
    message: `Owner's manual generated: ${driveLink}`,
    priority: 'info'
  }
}];

return [{
  json: {
    workflowName: 'SYS 09 — OS Owner\'s Manual Generator',
    contactName: '', phone: '', eventType: 'manual_generated', status: 'success',
    notes: 'Owner\'s manual PDF generated and uploaded'
  }
}];

